def load_evaluation_guidelines(guidelines_path: str) -> Dict[str, str]:
    """
    Load evaluation guidelines from YAML file.

    Returns:
        Dict mapping criterion name -> guideline text.
    """
    with open(guidelines_path, "r") as f:
        data = yaml.safe_load(f)

    guideline_map: Dict[str, str] = {}
    for criterion in data.get("evaluation_criteria", []):
        name = criterion.get("name")
        guideline = criterion.get("guideline", "")
        if name:
            guideline_map[name] = guideline.strip()

    return guideline_map


GUIDELINE_MAP = load_evaluation_guidelines(GUIDELINES_PATH)

print(f"✅ Loaded {len(GUIDELINE_MAP)} evaluation guidelines from {GUIDELINES_PATH}")
