@dataclass
class JudgeResult:
    """Result of a single LLM judge evaluation."""
    criterion: str
    verdict: str          # "yes" or "no"
    reasoning: str        # Short explanation from the judge
    passed: bool          # True if verdict == "yes"


class LLMJudge:
    """
    LLM-based judge for evaluating metabolic readiness message quality.

    The judge is called once per criterion per message. It receives:
    - The criterion name and full guideline
    - The user context (health data used to generate the message)
    - The generated message
    - The selected content summary (what logic engine chose)

    It returns a binary yes/no verdict with a short reasoning explanation.
    """

    # Judge system prompt — tells the model its role and output format
    SYSTEM_PROMPT = """You are a clinical quality evaluator for a digital health coaching application.
Your task is to evaluate personalized health messages generated by an AI assistant against specific quality criteria.

For each evaluation:
1. Read the criterion guideline carefully.
2. Review the user's health data context, the selected content summary, and the generated message.
3. Make a binary judgment: does the message PASS ("yes") or FAIL ("no") this criterion?
4. Provide a brief, specific reasoning (1-3 sentences) explaining your verdict.

IMPORTANT RULES:
- Be strict and consistent. If ANY part of the criterion is violated, mark as "no".
- Base your judgment only on the message content and the provided context.
- Do not infer or assume information not present.
- Your response MUST be valid JSON with exactly two fields: "verdict" ("yes" or "no") and "reasoning" (string).
- Do not include any text outside the JSON object.

Example output:
{"verdict": "yes", "reasoning": "The message uses warm, encouraging language throughout with no clinical or robotic phrasing."}
"""

    def __init__(self, judge_model_name: str, guideline_map: Dict[str, str]):
        self.judge_model_name = judge_model_name
        self.guideline_map = guideline_map
        self._client = None

    def _get_client(self):
        """Lazy-initialize the Databricks workspace client."""
        if self._client is None:
            from databricks.sdk import WorkspaceClient
            self._client = WorkspaceClient()
        return self._client

    def evaluate_criterion(
        self,
        criterion: str,
        message: str,
        user_context: Dict[str, Any],
        selected_content: Dict[str, Any],
    ) -> JudgeResult:
        """
        Evaluate a single message against one criterion.

        Args:
            criterion: Criterion name (must exist in guideline_map).
            message: The generated health message text.
            user_context: Flat dict of user health features.
            selected_content: Summary of what the logic engine selected.

        Returns:
            JudgeResult with verdict and reasoning.
        """
        guideline = self.guideline_map.get(criterion, "No guideline available.")

        user_prompt = self._build_user_prompt(
            criterion=criterion,
            guideline=guideline,
            message=message,
            user_context=user_context,
            selected_content=selected_content,
        )

        try:
            from databricks.sdk.service.serving import ChatMessage, ChatMessageRole

            client = self._get_client()
            response = client.serving_endpoints.query(
                name=self.judge_model_name,
                messages=[
                    ChatMessage(role=ChatMessageRole.SYSTEM, content=self.SYSTEM_PROMPT),
                    ChatMessage(role=ChatMessageRole.USER, content=user_prompt),
                ],
                max_tokens=300,
                temperature=0.0,  # Deterministic for consistent evaluation
            )

            raw_text = response.choices[0].message.content.strip()
            result = self._parse_judge_response(raw_text)
            verdict = result.get("verdict", "no").lower().strip()
            reasoning = result.get("reasoning", "No reasoning provided.")

        except Exception as e:
            logger.error(f"Judge error for criterion '{criterion}': {e}")
            verdict = "error"
            reasoning = f"Evaluation error: {str(e)}"

        passed = verdict == "yes"
        return JudgeResult(
            criterion=criterion,
            verdict=verdict,
            reasoning=reasoning,
            passed=passed,
        )

    def evaluate_all_criteria(
        self,
        message: str,
        user_context: Dict[str, Any],
        selected_content: Dict[str, Any],
        criteria: Optional[List[str]] = None,
    ) -> Dict[str, JudgeResult]:
        """
        Evaluate a message against all (or a subset of) criteria.

        Args:
            message: The generated health message text.
            user_context: Flat dict of user health features.
            selected_content: Summary of what the logic engine selected.
            criteria: List of criteria to evaluate. Defaults to all loaded guidelines.

        Returns:
            Dict mapping criterion name -> JudgeResult.
        """
        criteria_to_eval = criteria or list(self.guideline_map.keys())
        results: Dict[str, JudgeResult] = {}

        for criterion in criteria_to_eval:
            logger.info(f"  Evaluating criterion: {criterion}")
            results[criterion] = self.evaluate_criterion(
                criterion=criterion,
                message=message,
                user_context=user_context,
                selected_content=selected_content,
            )

        return results

    # ------------------------------------------------------------------
    # Private helpers
    # ------------------------------------------------------------------

    @staticmethod
    def _build_user_prompt(
        criterion: str,
        guideline: str,
        message: str,
        user_context: Dict[str, Any],
        selected_content: Dict[str, Any],
    ) -> str:
        """Build the user-facing prompt for the judge."""
        # Serialize context dicts — exclude excessively large keys
        context_str = json.dumps(
            {k: v for k, v in user_context.items() if v is not None},
            indent=2,
            default=str,
        )
        selected_str = json.dumps(selected_content, indent=2, default=str)

        return f"""=== CRITERION TO EVALUATE ===
Name: {criterion}

=== EVALUATION GUIDELINE ===
{guideline}

=== USER HEALTH DATA CONTEXT ===
{context_str}

=== LOGIC ENGINE SELECTED CONTENT ===
{selected_str}

=== GENERATED MESSAGE TO EVALUATE ===
{message}

=== TASK ===
Evaluate whether the GENERATED MESSAGE passes the criterion above.
Respond with valid JSON only: {{"verdict": "yes" or "no", "reasoning": "brief explanation"}}"""

    @staticmethod
    def _parse_judge_response(raw_text: str) -> Dict[str, str]:
        """Parse the JSON response from the judge model."""
        # Strip markdown code fences if present
        cleaned = re.sub(r"```(?:json)?\s*", "", raw_text).strip().rstrip("`").strip()
        try:
            return json.loads(cleaned)
        except json.JSONDecodeError:
            # Attempt to extract verdict with regex as fallback
            verdict_match = re.search(r'"verdict"\s*:\s*"(yes|no)"', cleaned, re.IGNORECASE)
            reasoning_match = re.search(r'"reasoning"\s*:\s*"([^"]+)"', cleaned)
            return {
                "verdict": verdict_match.group(1) if verdict_match else "no",
                "reasoning": reasoning_match.group(1) if reasoning_match else "Could not parse judge response.",
            }


