def load_test_cases(csv_path: str) -> pd.DataFrame:
    """
    Load TestCases.csv and return a cleaned DataFrame with normalised scenario columns.

    Expected CSV columns (from the file header):
        Column A: Area of Focus
        Expectation
        Column B: Weight
        Column C: Glucose
        Column D: Activity
        Column E: Steps
        Column F: Food
        Column G: Sleep
        Column H: Medications
        Column I: Mental Well-being
        Column J: Explore
        Column K: Journey
        Daily Message  (expected output — kept for reference)
    """
    raw = pd.read_csv(csv_path)
    raw.columns = raw.columns.str.strip()

    # Rename to consistent internal names
    col_map = {
        "Column A: Area of Focus": "area_of_focus",
        "Expectation":             "expectation",
        "Column B: Weight":        "weight_scenario",
        "Column C: Glucose":       "glucose_scenario",
        "Column D: Activity":      "activity_scenario",
        "Column E: Steps":         "step_scenario",
        "Column F: Food":          "food_scenario",
        "Column G: Sleep":         "sleep_scenario",
        "Column H: Medications":   "med_scenario",
        "Column I: Mental Well-being": "mental_scenario",
        "Column J: Explore":       "explore_scenario",
        "Column K: Journey":       "journey_scenario",
        "Daily Message":           "expected_message",
    }
    raw = raw.rename(columns={k: v for k, v in col_map.items() if k in raw.columns})

    # Drop completely empty rows (e.g. trailing blank rows in the CSV)
    raw = raw.dropna(subset=["area_of_focus"], how="all")
    raw = raw[raw["area_of_focus"].str.strip().str.len() > 0].reset_index(drop=True)

    # Normalise each scenario column
    raw["weight_scenario"]   = raw["weight_scenario"].apply(
        lambda v: _normalise(str(v).strip(), WEIGHT_NORM,   "Weight",   list(WEIGHT_SCENARIOS.keys())))
    raw["glucose_scenario"]  = raw["glucose_scenario"].apply(
        lambda v: _normalise(str(v).strip(), GLUCOSE_NORM,  "Glucose",  list(GLUCOSE_SCENARIOS.keys())))
    raw["activity_scenario"] = raw["activity_scenario"].apply(
        lambda v: _normalise(str(v).strip(), ACTIVITY_NORM, "Activity", list(ACTIVITY_SCENARIOS.keys())))
    raw["step_scenario"]     = raw["step_scenario"].apply(
        lambda v: _normalise(str(v).strip(), STEP_NORM,     "Steps",    list(STEP_SCENARIOS.keys())))
    raw["food_scenario"]     = raw["food_scenario"].apply(
        lambda v: _normalise(str(v).strip(), FOOD_NORM,     "Food",     list(FOOD_SCENARIOS.keys())))
    raw["sleep_scenario"]    = raw["sleep_scenario"].apply(
        lambda v: _normalise(str(v).strip(), SLEEP_NORM,    "Sleep",    list(SLEEP_SCENARIOS.keys())))
    raw["med_scenario"]      = raw["med_scenario"].apply(
        lambda v: _normalise(str(v).strip(), MED_NORM,      "Meds",     list(MED_SCENARIOS.keys())))
    raw["mental_scenario"]   = raw["mental_scenario"].apply(
        lambda v: _normalise(str(v).strip(), MENTAL_NORM,   "Mental",   list(MENTAL_WELLBEING_SCENARIOS.keys())))
    raw["explore_scenario"]  = raw["explore_scenario"].apply(
        lambda v: _normalise(str(v).strip(), EXPLORE_NORM,  "Explore",  list(EXPLORE_SCENARIOS.keys())))
    raw["journey_scenario"]  = raw["journey_scenario"].apply(
        lambda v: _normalise(str(v).strip(), JOURNEY_NORM,  "Journey",  list(JOURNEY_SCENARIOS.keys())))

    # Derive user_focus list from area_of_focus label
    raw["user_focus"] = raw["area_of_focus"].apply(_derive_user_focus)

    # Apply substitutions for unsupported scenarios — replace with neutral defaults
    # instead of dropping the row so the rest of the scenario is still evaluated.
    total_substitutions = 0
    for col, sub_map in UNSUPPORTED_SCENARIO_SUBSTITUTIONS.items():
        if col in raw.columns:
            mask = raw[col].isin(sub_map)
            if mask.any():
                raw.loc[mask, col] = raw.loc[mask, col].map(sub_map)
                total_substitutions += mask.sum()
    if total_substitutions:
        logger.info(
            f"  ℹ️  Substituted {total_substitutions} unsupported scenario value(s) with neutral defaults "
            f"(see UNSUPPORTED_SCENARIO_SUBSTITUTIONS)"
        )

    return raw


