def build_user_contexts_from_csv(df: pd.DataFrame) -> List[Dict[str, Any]]:
    """
    For each row in the test cases DataFrame, call generate_synthetic_context()
    from backend.py to produce a realistic UserContext, then return a list of
    enriched dicts ready for the evaluation loop.

    Each output dict contains:
        - user_context: UserContext object
        - test_id:      row number (1-based)
        - test_label:   area_of_focus value
        - expectation:  what the message should achieve (from CSV)
        - scenarios:    dict of scenario labels used
    """
    contexts = []

    for idx, row in df.iterrows():
        test_id = idx + 1

        # Build UserContext via synthetic data generator (same as testing tool)
        user_ctx = generate_synthetic_context(
            user_focus=row["user_focus"],
            weight_scenario=row["weight_scenario"],
            glucose_scenario=row["glucose_scenario"],
            activity_scenario=row["activity_scenario"],
            step_scenario=row["step_scenario"],
            food_scenario=row["food_scenario"],
            sleep_scenario=row["sleep_scenario"],
            med_scenario=row["med_scenario"],
            mental_scenario=row["mental_scenario"],
            explore_scenario=row["explore_scenario"],
            journey_scenario=row["journey_scenario"],
        )

        # Give each synthetic user a deterministic test ID for traceability
        user_ctx.patient_id = f"TEST-{str(test_id).zfill(3)}"

        contexts.append({
            "test_id":     test_id,
            "test_label":  str(row.get("area_of_focus", f"Case {test_id}")),
            "expectation": str(row.get("expectation", "")),
            "user_context": user_ctx,
            "scenarios": {
                "weight":   row["weight_scenario"],
                "glucose":  row["glucose_scenario"],
                "activity": row["activity_scenario"],
                "steps":    row["step_scenario"],
                "food":     row["food_scenario"],
                "sleep":    row["sleep_scenario"],
                "meds":     row["med_scenario"],
                "mental":   row["mental_scenario"],
                "explore":  row["explore_scenario"],
                "journey":  row["journey_scenario"],
            },
        })

    return contexts


