def generate_summary(
    results: List[Dict[str, Any]],
    criteria_categories: Dict[str, List[str]],
    evaluation_criteria: List[str],
) -> Dict[str, Any]:
    """
    Generate summary statistics from evaluation results.

    Returns a dict with overall, category-level, and criterion-level pass rates.
    """
    n = len(results)
    if n == 0:
        return {}

    # Overall
    overall_pass_rate = sum(r["pass_rate"] for r in results) / n

    # Per-criterion stats
    criterion_stats: Dict[str, Dict[str, Any]] = {}
    for criterion in evaluation_criteria:
        col = f"{criterion}_passed"
        passed = sum(1 for r in results if r.get(col, False))
        criterion_stats[criterion] = {
            "passed": passed,
            "total": n,
            "pass_rate": passed / n,
        }

    # Per-category stats
    category_stats: Dict[str, Dict[str, Any]] = {}
    for category, criteria in criteria_categories.items():
        cat_rates = [criterion_stats[c]["pass_rate"] for c in criteria if c in criterion_stats]
        category_stats[category] = {
            "avg_pass_rate": sum(cat_rates) / len(cat_rates) if cat_rates else 0.0,
            "criteria_count": len(criteria),
        }

    return {
        "total_cases": n,
        "overall_pass_rate": overall_pass_rate,
        "criterion_stats": criterion_stats,
        "category_stats": category_stats,
    }


def print_summary(summary: Dict[str, Any]):
    """Print a formatted evaluation summary."""
    print("\n" + "=" * 70)
    print("📊 METABOLIC READINESS EVALUATION SUMMARY")
    print("=" * 70)
    print(f"  Total test cases:   {summary['total_cases']}")
    print(f"  Overall pass rate:  {summary['overall_pass_rate']:.1%}")

    print("\n📁 CATEGORY PASS RATES:")
    print("-" * 50)
    for category, stats in summary["category_stats"].items():
        bar = "█" * int(stats["avg_pass_rate"] * 20)
        print(f"  {category:<28} {stats['avg_pass_rate']:>5.1%}  {bar}")

    print("\n📋 CRITERION PASS RATES:")
    print("-" * 70)
    print(f"  {'Criterion':<45} {'Passed':>6}  {'Rate':>6}")
    print("-" * 70)
    for criterion, stats in summary["criterion_stats"].items():
        status = "✅" if stats["pass_rate"] >= 0.8 else ("⚠️ " if stats["pass_rate"] >= 0.5 else "❌")
        print(f"  {status} {criterion:<43} {stats['passed']:>3}/{stats['total']:<3}  {stats['pass_rate']:>5.1%}")

    print("\n⚠️  CRITERIA NEEDING IMPROVEMENT (pass rate < 80%):")
    low_perf = {k: v for k, v in summary["criterion_stats"].items() if v["pass_rate"] < 0.8}
    if low_perf:
        for criterion, stats in sorted(low_perf.items(), key=lambda x: x[1]["pass_rate"]):
            print(f"  - {criterion}: {stats['pass_rate']:.1%}")
    else:
        print("  None — all criteria above 80%!")


summary = generate_summary(evaluation_results, CRITERIA_CATEGORIES, EVALUATION_CRITERIA)
print_summary(summary)

