class ExcelReportGenerator:
    """
    Generates a formatted Excel report from the evaluation results.

    Workbook structure:
    - Sheet 1: Summary — overall and per-category/criterion pass rates
    - Sheet 2: Detailed Results — one row per test case with all criteria verdicts
    - Sheet 3: Messages — full generated message text per case
    """

    # Color palette
    COLOR_PASS = "C6EFCE"       # Light green
    COLOR_FAIL = "FFC7CE"       # Light red
    COLOR_ERROR = "FFEB9C"      # Light yellow
    COLOR_HEADER = "1F4E79"     # Dark blue
    COLOR_SUBHEADER = "2E75B6"  # Medium blue
    COLOR_CATEGORY = "D6E4F0"   # Light blue

    def __init__(
        self,
        criteria_categories: Dict[str, List[str]],
        evaluation_criteria: List[str],
    ):
        self.criteria_categories = criteria_categories
        self.evaluation_criteria = evaluation_criteria

    def generate(self, results: List[Dict[str, Any]], output_path: str):
        """Generate the Excel report and save to output_path."""
        wb = Workbook()

        self._build_summary_sheet(wb, results)
        self._build_detail_sheet(wb, results)
        self._build_messages_sheet(wb, results)

        # Remove default sheet
        if "Sheet" in wb.sheetnames:
            del wb["Sheet"]

        wb.save(output_path)
        print(f"✅ Excel report saved: {output_path}")

    # ------------------------------------------------------------------
    # Sheet builders
    # ------------------------------------------------------------------

    def _build_summary_sheet(self, wb: Workbook, results: List[Dict[str, Any]]):
        """Build the Summary sheet with overall stats and per-criterion breakdown."""
        ws = wb.create_sheet("Summary", 0)

        # --- Title ---
        ws.merge_cells("A1:E1")
        title_cell = ws["A1"]
        title_cell.value = "Metabolic Readiness Message Quality Evaluation — Summary"
        title_cell.font = Font(bold=True, size=14, color="FFFFFF")
        title_cell.fill = PatternFill("solid", fgColor=self.COLOR_HEADER)
        title_cell.alignment = Alignment(horizontal="center", vertical="center")
        ws.row_dimensions[1].height = 30

        # --- Overall stats ---
        n = len(results)
        overall_pass_rate = sum(r["pass_rate"] for r in results) / n if n > 0 else 0.0

        ws["A3"] = "Total Test Cases"
        ws["B3"] = n
        ws["A4"] = "Overall Pass Rate"
        ws["B4"] = f"{overall_pass_rate:.1%}"
        ws["A5"] = "Evaluation Date"
        ws["B5"] = datetime.now().strftime("%Y-%m-%d %H:%M")
        ws["A6"] = "Judge Model"
        ws["B6"] = JUDGE_MODEL_NAME

        for row in range(3, 7):
            ws[f"A{row}"].font = Font(bold=True)

        # --- Category section ---
        row_idx = 9
        ws[f"A{row_idx}"] = "Category"
        ws[f"B{row_idx}"] = "# Criteria"
        ws[f"C{row_idx}"] = "Avg Pass Rate"
        for col in ["A", "B", "C"]:
            cell = ws[f"{col}{row_idx}"]
            cell.font = Font(bold=True, color="FFFFFF")
            cell.fill = PatternFill("solid", fgColor=self.COLOR_SUBHEADER)
        row_idx += 1

        for category, criteria in self.criteria_categories.items():
            cat_rates = []
            for r in results:
                case_rates = [1 if r.get(f"{c}_passed", False) else 0 for c in criteria]
                cat_rates.append(sum(case_rates) / len(criteria) if criteria else 0)
            avg_rate = sum(cat_rates) / len(cat_rates) if cat_rates else 0.0

            ws[f"A{row_idx}"] = category
            ws[f"B{row_idx}"] = len(criteria)
            ws[f"C{row_idx}"] = f"{avg_rate:.1%}"
            ws[f"A{row_idx}"].fill = PatternFill("solid", fgColor=self.COLOR_CATEGORY)
            ws[f"B{row_idx}"].fill = PatternFill("solid", fgColor=self.COLOR_CATEGORY)
            result_cell = ws[f"C{row_idx}"]
            result_cell.fill = PatternFill("solid", fgColor=self.COLOR_CATEGORY)
            if avg_rate >= 0.8:
                result_cell.font = Font(bold=True, color="375623")
            elif avg_rate < 0.5:
                result_cell.font = Font(bold=True, color="9C0006")
            row_idx += 1

        # --- Per-criterion section ---
        row_idx += 1
        ws[f"A{row_idx}"] = "Criterion"
        ws[f"B{row_idx}"] = "Category"
        ws[f"C{row_idx}"] = "Passed"
        ws[f"D{row_idx}"] = "Total"
        ws[f"E{row_idx}"] = "Pass Rate"
        for col in ["A", "B", "C", "D", "E"]:
            cell = ws[f"{col}{row_idx}"]
            cell.font = Font(bold=True, color="FFFFFF")
            cell.fill = PatternFill("solid", fgColor=self.COLOR_SUBHEADER)
        row_idx += 1

        category_lookup = {
            c: cat
            for cat, criteria in self.criteria_categories.items()
            for c in criteria
        }

        for criterion in self.evaluation_criteria:
            col_key = f"{criterion}_passed"
            passed = sum(1 for r in results if r.get(col_key, False))
            total = len(results)
            rate = passed / total if total > 0 else 0.0

            ws[f"A{row_idx}"] = criterion
            ws[f"B{row_idx}"] = category_lookup.get(criterion, "")
            ws[f"C{row_idx}"] = passed
            ws[f"D{row_idx}"] = total
            rate_cell = ws[f"E{row_idx}"]
            rate_cell.value = f"{rate:.1%}"
            if rate >= 0.8:
                rate_cell.fill = PatternFill("solid", fgColor=self.COLOR_PASS)
            elif rate < 0.5:
                rate_cell.fill = PatternFill("solid", fgColor=self.COLOR_FAIL)
            else:
                rate_cell.fill = PatternFill("solid", fgColor=self.COLOR_ERROR)
            row_idx += 1

        # Column widths
        ws.column_dimensions["A"].width = 48
        ws.column_dimensions["B"].width = 25
        ws.column_dimensions["C"].width = 12
        ws.column_dimensions["D"].width = 8
        ws.column_dimensions["E"].width = 12

    def _build_detail_sheet(self, wb: Workbook, results: List[Dict[str, Any]]):
        """Build the Detailed Results sheet with one row per test case."""
        ws = wb.create_sheet("Detailed Results", 1)

        # Headers
        base_headers = ["#", "Patient ID", "Test Label", "Expectation", "Daily Rating", "Pass Rate", "Passed / Total"]
        criterion_headers = []
        for criterion in self.evaluation_criteria:
            criterion_headers.append(f"{criterion}\n(verdict)")
            criterion_headers.append(f"{criterion}\n(reasoning)")

        all_headers = base_headers + criterion_headers
        for col_idx, header in enumerate(all_headers, start=1):
            cell = ws.cell(row=1, column=col_idx, value=header)
            cell.font = Font(bold=True, color="FFFFFF", size=9)
            cell.fill = PatternFill("solid", fgColor=self.COLOR_HEADER)
            cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
        ws.row_dimensions[1].height = 40

        # Data rows
        for row_idx, record in enumerate(results, start=2):
            pass_rate = record.get("pass_rate", 0.0)
            ws.cell(row=row_idx, column=1, value=record.get("test_id", ""))
            ws.cell(row=row_idx, column=2, value=record.get("patient_id", ""))
            ws.cell(row=row_idx, column=3, value=record.get("test_label", ""))
            expectation_cell = ws.cell(row=row_idx, column=4, value=record.get("expectation", ""))
            expectation_cell.alignment = Alignment(wrap_text=True, vertical="top")
            ws.cell(row=row_idx, column=5, value=record.get("daily_rating", ""))
            rate_cell = ws.cell(row=row_idx, column=6, value=f"{pass_rate:.1%}")
            rate_cell.fill = PatternFill(
                "solid",
                fgColor=self.COLOR_PASS if pass_rate >= 0.8 else (
                    self.COLOR_FAIL if pass_rate < 0.5 else self.COLOR_ERROR
                ),
            )
            ws.cell(
                row=row_idx,
                column=7,
                value=f"{record.get('passed_count', 0)}/{record.get('total_criteria', 0)}",
            )

            col_offset = len(base_headers) + 1
            for criterion in self.evaluation_criteria:
                verdict = record.get(f"{criterion}_verdict", "error")
                reasoning = record.get(f"{criterion}_reasoning", "")
                passed = record.get(f"{criterion}_passed", False)

                verdict_cell = ws.cell(row=row_idx, column=col_offset, value=verdict)
                verdict_cell.alignment = Alignment(horizontal="center")
                if verdict == "yes":
                    verdict_cell.fill = PatternFill("solid", fgColor=self.COLOR_PASS)
                elif verdict == "no":
                    verdict_cell.fill = PatternFill("solid", fgColor=self.COLOR_FAIL)
                else:
                    verdict_cell.fill = PatternFill("solid", fgColor=self.COLOR_ERROR)
                col_offset += 1

                reasoning_cell = ws.cell(row=row_idx, column=col_offset, value=reasoning)
                reasoning_cell.alignment = Alignment(wrap_text=True)
                col_offset += 1

            ws.row_dimensions[row_idx].height = 60

        # Column widths
        ws.column_dimensions["A"].width = 6   # #
        ws.column_dimensions["B"].width = 12  # Patient ID
        ws.column_dimensions["C"].width = 30  # Test Label
        ws.column_dimensions["D"].width = 40  # Expectation
        ws.column_dimensions["E"].width = 14  # Daily Rating
        ws.column_dimensions["F"].width = 12  # Pass Rate
        ws.column_dimensions["G"].width = 14  # Passed / Total
        for col_idx in range(len(base_headers) + 1, len(all_headers) + 1):
            col_letter = get_column_letter(col_idx)
            # Verdict columns narrow, reasoning columns wide
            ws.column_dimensions[col_letter].width = (
                12 if (col_idx - len(base_headers)) % 2 == 1 else 40
            )

        ws.freeze_panes = "H2"

    def _build_messages_sheet(self, wb: Workbook, results: List[Dict[str, Any]]):
        """Build the Messages sheet showing full generated text per test case."""
        ws = wb.create_sheet("Generated Messages", 2)

        headers = [
            "#", "Patient ID", "Test Label", "Expectation",
            "Daily Rating", "Word Count", "Pass Rate",
            "Generated Message", "Scenarios (JSON)"
        ]
        for col_idx, header in enumerate(headers, start=1):
            cell = ws.cell(row=1, column=col_idx, value=header)
            cell.font = Font(bold=True, color="FFFFFF")
            cell.fill = PatternFill("solid", fgColor=self.COLOR_HEADER)
            cell.alignment = Alignment(horizontal="center", vertical="center", wrap_text=True)
        ws.row_dimensions[1].height = 30

        for row_idx, record in enumerate(results, start=2):
            pass_rate = record.get("pass_rate", 0.0)
            ws.cell(row=row_idx, column=1, value=record.get("test_id", ""))
            ws.cell(row=row_idx, column=2, value=record.get("patient_id", ""))
            ws.cell(row=row_idx, column=3, value=record.get("test_label", ""))
            exp_cell = ws.cell(row=row_idx, column=4, value=record.get("expectation", ""))
            exp_cell.alignment = Alignment(wrap_text=True, vertical="top")
            ws.cell(row=row_idx, column=5, value=record.get("daily_rating", ""))
            ws.cell(row=row_idx, column=6, value=record.get("word_count", 0))
            rate_cell = ws.cell(row=row_idx, column=7, value=f"{pass_rate:.1%}")
            rate_cell.fill = PatternFill(
                "solid",
                fgColor=self.COLOR_PASS if pass_rate >= 0.8 else (
                    self.COLOR_FAIL if pass_rate < 0.5 else self.COLOR_ERROR
                ),
            )
            msg_cell = ws.cell(row=row_idx, column=8, value=record.get("generated_message", ""))
            msg_cell.alignment = Alignment(wrap_text=True, vertical="top")
            ws.cell(row=row_idx, column=9, value=record.get("scenarios", ""))
            ws.row_dimensions[row_idx].height = 100

        ws.column_dimensions["A"].width = 6
        ws.column_dimensions["B"].width = 12
        ws.column_dimensions["C"].width = 28
        ws.column_dimensions["D"].width = 40
        ws.column_dimensions["E"].width = 14
        ws.column_dimensions["F"].width = 10
        ws.column_dimensions["G"].width = 12
        ws.column_dimensions["H"].width = 70
        ws.column_dimensions["I"].width = 50
        ws.freeze_panes = "H2"


