# MAGIC ## 13. Detailed Analysis by Criterion

# COMMAND ----------

def print_failure_analysis(results: List[Dict[str, Any]], evaluation_criteria: List[str]):
    """
    Print a detailed failure analysis showing which cases failed each criterion
    and the judge's reasoning.
    """
    print("\n" + "=" * 70)
    print("🔍 FAILURE ANALYSIS BY CRITERION")
    print("=" * 70)

    for criterion in evaluation_criteria:
        failures = [
            r for r in results
            if not r.get(f"{criterion}_passed", False) and r.get(f"{criterion}_verdict") != "error"
        ]
        if not failures:
            print(f"\n✅ {criterion} — ALL PASSED")
            continue

        total = len(results)
        print(f"\n❌ {criterion} — {len(failures)}/{total} failed")
        print("-" * 60)
        for record in failures:
            print(f"  Case: {record.get('test_label', record.get('patient_id', ''))}")
            print(f"  Reason: {record.get(f'{criterion}_reasoning', 'N/A')}")
            print()


print_failure_analysis(evaluation_results, EVALUATION_CRITERIA)

